import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,a as e}from"./app-378b7e1a.js";const t={},l=e(`<h1 id="az-informacio-elrejtese" tabindex="-1"><a class="header-anchor" href="#az-informacio-elrejtese" aria-hidden="true">#</a> Az információ elrejtése</h1><div class="hint-container note"><p class="hint-container-title">Röviden</p><ul><li>Az információ elrejtése azt jelenti, hogy a részleteket nem tesszük hozzáférhetővé a külső kódnak.</li><li>Az osztálytagok hozzáférhetőségét a <code>public</code> vagy <code>private</code> kulcsszavakkal határozhatjuk meg, attól függően, hogy melyiket akarjuk használni.</li><li>Absztrakció.</li><li>A harmadik hozzáférhetőségi szint az <code>internal</code>.</li></ul></div><p>Most pedig az objektumorientált programozás két alapvető fogalmát fogjuk megnézni: az <strong>információ elrejtést</strong> és az <strong>absztrakciót</strong>.</p><p>Láttuk, hogy az <strong>encapsuláció</strong> segítségével egy objektum felelős lehet a rendszer egy részéért, saját adatait speciális változókban tárolhatja, amelyeket mezőknek nevezünk és saját képességeinek listáját adhatja meg metódusok formájában.</p><p>Második elvünk az <strong>encapsuláció</strong> egyszerű kiterjesztése (<em>néhányan ugyanannak tekintik</em>):</p><div class="hint-container tip"><p class="hint-container-title">Objektumorientált elv #2</p><p>Információelrejtés - Csak az objektum maga férhet hozzá közvetlenül az adataihoz.</p></div><p>Hogy ez miért fontos, tekintsük az alábbi kódot:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Rectangle</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">;</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">;</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> area<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token function">Rectangle</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> area<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> width<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> height<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>area <span class="token operator">=</span> area<span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez talán jó kezdés is lehetne, de van egy probléma. Egy téglalap területét a szélességének és a magasságának szorzatával kapjuk. Tehát ha a téglalap <em>szélessége: 1</em> és <em>magassága: 1</em> akkor a téglalap <em>területe: 1</em>. Viszont a téglalap jelenlegi meghatározásunk alapján ez is lehetséges:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name">Rectangle</span> rectangle <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Rectangle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">200000</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Nem lenne jó, ha betudnánk vezetni ezt a fajta szabályt! A terület paraméter eltávolítása a konstruktorból, megakadályozza, hogy valaki (<em>beleértve minket is, amikor három hét múlva elfelejtjük a részleteket</em> 🙄) véletlenül értelmetlen területet adjon meg. Magát a területet pedig a konstruktoron belül fogjuk kiszámolni:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Rectangle</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">;</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">;</span>
    <span class="token keyword">public</span> <span class="token class-name"><span class="token keyword">float</span></span> area<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token function">Rectangle</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> width<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> height<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez biztosítja, hogy az új téglalapok mindig a megfelelő területtel legyenek létrehozva. De még mindig van egy problémánk:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name">Rectangle</span> rectangle <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Rectangle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
rectangle<span class="token punctuation">.</span>area <span class="token operator">=</span> <span class="token number">200000</span><span class="token punctuation">;</span>
Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>rectangle<span class="token punctuation">.</span>area<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez a kód helyesen számolja ki a területet kezdetben, de nem akadályozza meg semmi abban, hogy valaki szándékosan vagy véletlenül megváltoztassa az értékét. Kívülről beavatkozhatunk és olyan módon manipulálhatjuk a téglalap adatait ahogy csak akarjuk viszont ez nem megengedett.</p><p>Ha a <code>Rectangle</code> osztálynak elrejtenénk az adatait, akkor kívülről nem tudnánk logikátlan vagy ellentmondó állapotokba hozni. Természetesen néha szükségünk lesz kívülről elérni a téglalap szélességét, magasságát és területét és talán meg is akarjuk majd változtatni a méretét, de mindez megvédhető metódusokkal.</p><h2 id="a-public-es-private-modositok" tabindex="-1"><a class="header-anchor" href="#a-public-es-private-modositok" aria-hidden="true">#</a> A <code>public</code> és <code>private</code> módosítók</h2><p>Amikor elkezdtünk osztályokat készíteni, minden mezőnkre és metódusunkra beállítottuk a <code>public</code>-ot. Ez a problémánk gyökere mert lehetővé teszi, hogy a kívülről elérjük azokat.</p><p>Az osztály minden tagjának - <em>tehát a mezőknek és metódusoknak egyaránt</em> - van egy hozzáférési szintje. Ez a szint határozza meg, hogy honnan érhető el az adott tag. A <code>public</code> kulcsszó a tagot <strong>nyilvános hozzáférhetőséggel</strong> ruházza fel - ami azt jelenti, hogy bárhol használható.</p><p>A <code>public</code> helyett használhatnánk a <code>private</code> kulcsszót is, amely a tagot <strong>privát hozzáférhetőséggel</strong> látja el - csak az osztályon belül használható. A <code>public</code> és a <code>private</code> kulcsszavak mind <strong>hozzáférési módosítóknak nevezhetők</strong>, mert megváltoztatja az adott tag hozzáférési szintjét. Ha a mezőinket priváttá tesszük, akkor a kívülről közvetlenül nem érjük el:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Rectangle</span>
<span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> area<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token function">Rectangle</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> width<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> height<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span> 
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az adataink mostantól <code>pirvate</code>-ok. Az osztályon belül továbbra is használhatjuk a mezőket, mivel a konstruktor inicializálja őket. A tagok priváttá tétele biztosítja, hogy kívülről ne tudjuk megváltoztatni azokat. Továbbá ne tudjunk létre hozni értelmetlen téglalapokat sem.</p><p><strong>De most az ellenkező problémánk van.</strong> Elzártuk az összes hozzáférést ezekhez a tagokhoz. A kívülről valamilyen láthatóságot és talán némi irányítást szeretnénk a téglalapok felett. Minden mezőnket privátnak jelöltük, így már ezt sem tudjuk megtenni:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name">Rectangle</span> rectangle <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Rectangle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>rectangle<span class="token punctuation">.</span>area<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// DOESN&#39;T COMPILE!</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha a kívülről elszeretnénk érni a téglalap területét, akkor azt jelenti, hogy a mezőt mindenképpen nyilvánossá kell tennünk?</p><p><strong>Általában nem.</strong></p><p>Ahelyett, hogy közvetlen hozzáférést engednénk a mezőinkhez, <strong>metódusokon</strong> keresztül biztosítunk ellenőrzött hozzáférést - <em>ha kívülről például elszeretnénk érni a téglalap szélességét, magasságát és területét</em>. Ezért ezeket a metódusokat hozzáadjuk a <code>Rectangle</code> osztályhoz:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetWidth</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> width<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetHeight</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> height<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> area<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">/* 
* public float GetWidth() =&gt; width;
* public float GetHeight() =&gt; height;
* public float GetArea() =&gt; area;
*/</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A mezők privátok maradnak és a kívülről továbbra is megkaphatjuk a kérdéseinkre a válaszokat, anélkül, hogy korlátlanul hozzáférhetnénk az adatokhoz.</p><p>Ha a kívülről szükségünk van arra is, hogy megváltoztassuk a téglalap méreteit, akkor ezt is megoldhatjuk metódusok segítségével:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetWidth</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    width <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
    area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetHeight</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    height <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
    area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ésszerű megoldani, hogy tudjuk frissítseni a szélességet és a magasságot, ezért ezeknek a tagokhoz létrehoztunk metódusokat.</p><p>Viszont nem akarjuk, hogy a közvetlenül módosíthassuk a területet, ezért azt kihagytuk. Szándékosan olyan neveket választottam, amelyek <code>Get</code>-tel és <code>Set</code>-tel kezdődnek.</p><p>A metódusok amelyek lekérik egy mező jelenlegi értékét <strong>gettereknek</strong>, amelyek új értéket rendelnek egy mezőhöz, <strong>settereknek</strong> hívjuk.</p><p>A fenti kódból látható, hogy ezek a metódusok többet tesznek lehetővé, mint a mező új értékének beállítása. Mind a <code>SetWidth</code>, mind a <code>SetHeight</code> frissíti a téglalap területét, hogy az összhangban maradjon a szélességével és magasságával.</p><p>Ezek a változtatások a következő <code>Rectangle</code> osztályt eredményezik:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Rectangle</span>
<span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> area<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token function">Rectangle</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> width<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> height<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetWidth</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        width <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
        area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetHeight</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        height <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
        area <span class="token operator">=</span> width <span class="token operator">*</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
        
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetWidth</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> width<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetHeight</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> area<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ezekkel a változtatásokkal, ha egy téglalapot akarunk létrehozni és megváltoztatni a méretét, akkor az új metódusokat használjuk:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name">Rectangle</span> rectangle <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">Rectangle</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
rectangle<span class="token punctuation">.</span><span class="token function">SetWidth</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>rectangle<span class="token punctuation">.</span><span class="token function">GetArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az információ elrejtése lehetővé teszi egy objektum számára, hogy megvédje az adatait. Az objektum állapotának lekérdezéséhez vagy módosításához nem megfelelő a közvetlen hozzáférés, ehelyett a <code>getter</code> vagy <code>setter</code> nevű metódusokat kell használnunk.<br> Így az objektumok betartják azokat az elveket, amelyeket az adataikra alkalmaznak, mint például a téglalap területének kiszámítása.</p><p>Az információ elrejtése lényegesen bonyolultabb - a <code>rectangle.SetWidth(3);</code> utasítás nehezebben érthető, mint a <code>rectangle.width = 3;</code>. Ez a megoldás jelenleg csak ideiglenes.</p><h3 id="az-alapertelmezett-lathatosagot-private" tabindex="-1"><a class="header-anchor" href="#az-alapertelmezett-lathatosagot-private" aria-hidden="true">#</a> Az alapértelmezett láthatóságot <code>private</code></h3><p>Minden osztálytagunkhoz <code>public</code> vagy <code>private</code> értéket adtunk de ez nem feltétlenül szükséges. Teljesen elhagyhatjuk ezeket ha nem adunk meg láthatóságot akkor az osztály tagjai <code>private</code>-ok lesznek.</p><p>A legtöbb esetben azt javaslom, hogy ne hagyjuk el. Mindig tegyük ki a <code>public</code> vagy a <code>private</code> láthatósági szinteket minden egyes osztálytagra. Ez arra kényszerít, hogy átgondoljuk, mennyire legyen elérhető az adott tag.</p><h3 id="mikor-hasznaljuk-a-private-es-public-lathatosagot" tabindex="-1"><a class="header-anchor" href="#mikor-hasznaljuk-a-private-es-public-lathatosagot" aria-hidden="true">#</a> Mikor használjuk a <code>private</code> és <code>public</code> láthatóságot?</h3><p>Két gyakori irányelv segít nekünk abban, hogy eldöntsük, mikor legyenek tagok <code>private</code>-ok vagy <code>public</code>-usak.</p><ol><li><p>Az első, amit korábban érintettünk, az az, hogy egy osztálynak védenie kell az adatait. A mezők szinte mindig privátoknak kell lenniük. Vannak kivételek, de ezek ritkák.</p></li><li><p>A második irányelv az, hogy a tagoknak mindig annyira kell hozzáférhetetleneknek lenniük, amennyire csak lehetséges, miközben az osztálynak még mindig képesnek kell lennie a betöltött szerepének teljesítésére.</p></li></ol><div class="hint-container tip"><p class="hint-container-title">Például mondhatnánk, hogy...</p><p>A legutóbbi <code>Rectangle</code> osztálydefiníciónkban a <code>getter</code>-ek és <code>setter</code>-ek a téglalap reprezentálásának részei. Ezért ésszerű, hogy ezek mindegyike <strong>publikus</strong> legyen, de jó pár alkalommal volt olyan kódsorunk, ami így nézett ki: <code>area = width * height;</code>. Készíthetnénk egy <code>UpdateArea</code> nevű metódust, amely tartalmazza ezt a logikát, majd három különböző helyen hívhatnánk meg (a konstruktorban, a <code>SetWidth</code>-ben és a <code>SetHeight</code>-ben).</p><p>Az <code>UpdateArea</code> privát vagy publikus legyen?</p><p>Az <code>area</code> frissítése nem olyasmi, amit a kívülről kifejezetten kérnünk kellene. Mivel a kívülről nem kell hozzáférni, ez az új metódus valószínűleg jobb lenne privát metódusként.</p></div><p>Néha előfordulhat, hogy rossz a hozzáférhetőségi szintet használunk majd de ez a szoftvertervezés része. Viszont később szerencsére ezt megváltoztathatjuk. Könnyebb valamit privátból publikussá tenni, mint fordítva. A kívülről már használhatunk valamit, amit kezdetben publikussá tettünk és azokat el kell majd távolítanunk.</p><h3 id="lathatosagi-szintek-iranymutatasok-nem-torvenyek" tabindex="-1"><a class="header-anchor" href="#lathatosagi-szintek-iranymutatasok-nem-torvenyek" aria-hidden="true">#</a> Láthatósági szintek iránymutatások, nem törvények</h3><p>Amikor valamit priváttá teszünk, az nem azt jelenti, hogy kívülről teljesen képtelenség használni. Egyedül azt jelzi, hogy a fordító segítségét kérjük annak biztosításában, hogy a privát elemek véletlenül se legyenek hozzáférhetők a kód más részei számára. Fordító hibákat hoz létre, ha megpróbálunk hozzáférni a privát tagokhoz.</p><h2 id="absztrakcio" tabindex="-1"><a class="header-anchor" href="#absztrakcio" aria-hidden="true">#</a> Absztrakció</h2><p>Egy osztály belső működése nem látható számunkra. Olyan ez, mint egy mobiltelefon belseje, amíg a telefon gombjai és képernyője működik, addig nem érdekel bennünket, hogyan működik a belső áramkör. Az emberi test is ilyen. Nem kell tudnunk, hogyan kapcsolódnak az idegek és az inak, amíg a dolgok megfelelően működnek.</p><p>Tehát egy objektum belső működése el van rejtve, így csak a kívánt információkat és funkciókat teszi elérhetővé. Ezáltal a belső folyamatokat szabadon módosíthatjuk anélkül, hogy ez befolyásolná a viselkedését. Ezt a képességet nevezzük <strong>absztrakciónak</strong>, ami az objektumorientált programozás egyik alapelve.</p><div class="hint-container tip"><p class="hint-container-title">Objektumorientált elv #3</p><p>Az absztrakció révén a belső működés megváltoztatható anélkül, hogy ez hatással lenne a környezetére.</p></div><p>Az absztrakció segít a nagy problémák kisebb részekre bontásában, így minden egyes részen külön-külön dolgozhatunk. Nem kell emlékeznünk a teljes program minden egyes részletére.</p><p>Illusztráljuk egy példával. A <code>Rectangle</code> osztály korábbi verzióiban volt egy mező a téglalap területére, amely minden alkalommal frissült, amikor a szélesség vagy a magasság változott. Ezt azonban megváltoztathatjuk úgy, hogy a területet csak szükség esetén számítsuk ki és a mezőt a programunk többi részének befolyásolása nélkül elhagyhatjuk:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">class</span> <span class="token class-name">Rectangle</span> 
<span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token function">Rectangle</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> width<span class="token punctuation">,</span> <span class="token class-name"><span class="token keyword">float</span></span> height<span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> width<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetWidth</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> width<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetHeight</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    
    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">float</span></span> <span class="token function">GetArea</span><span class="token punctuation">(</span><span class="token punctuation">)</span> 
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">*</span> <span class="token keyword">this</span><span class="token punctuation">.</span>height<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetWidth</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>width <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">SetHeight</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">float</span></span> <span class="token keyword">value</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>height <span class="token operator">=</span> <span class="token keyword">value</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>    
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <code>area</code> mező eltűnt és a <code>SetWidth</code>, <code>SetHeight</code>, valamint a konstruktor már nem számítja ki a területet. Ehelyett a terület kiszámítása igény szerint történik, amikor valaki meghívja a <code>GetArea</code> metódus. Kívülről nem fog látszódni ez a változtatás.</p><h2 id="tipusu-hozzaferhetosegi-szintek-es-az-internal" tabindex="-1"><a class="header-anchor" href="#tipusu-hozzaferhetosegi-szintek-es-az-internal" aria-hidden="true">#</a> Típusú hozzáférhetőségi szintek és az <code>internal</code></h2><p>A típusokhoz hozzáférési szinteket lehet (<strong>és kell is</strong>) rendelni:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Rectangle</span>
<span class="token punctuation">{</span>
<span class="token comment">// ...</span>
<span class="token punctuation">}</span>
</code></pre><div class="highlight-lines"><div class="highlight-line"> </div><br><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <code>private</code> hozzáférési szint nem alkalmazható és nem is releváns ilyen esetben, mivel az korlátozzná a használatot. Elsőre úgy tűnhet, hogy csak a <code>public</code> hozzáférési szint marad, de létezik egy másik lehetőség is: az <code>internal</code>.</p><p>A <code>public</code> és az <code>internal</code> közötti különbség elsőre nem tűnik nagynak. A <code>public</code> hozzáférési szinttel rendelkező elemek mindenhol elérhetők, beleértve más projekteket is, míg az <code>internal</code> csak a saját projektünkben használható. Gondoljunk például a <strong>.NET Base Class Library</strong> összes kódjára, mint a <code>Console</code> és a <code>Convert</code>. Ez a kód úgy lett kialakítva, hogy mindenhol újra használható legyen. A <code>Console</code> és a <code>Convert</code> mindkettő <code>public</code>.</p><p>Ha létrehozol egy új típust (osztályt, enumerációt, stb.) és úgy érzed, hogy ez támogató szerepet tölt be - amelyek segítik a többi osztály munkáját, de nem olyan, hogy a programon belül más osztály is ismerjen -, akkor az <code>internal</code> hozzáférési szintet választhatjuk erre a célra.</p><div class="hint-container note"><p class="hint-container-title">Jelenleg önálló programokat fejlesztünk. Nem hoztunk létre semmit, amit más projektektől elvárnánk, hogy újrahasználjanak. Elképzelhető, hogy azt gondolod: &quot;Nem várom el, hogy bárki más vagy én is újrahasználjam mindezt. Miért kellene bármit is publická tennem?&quot;</p></div><p>Ez egy ésszerű gondolkodásmód és néhányan azt javasolnák, hogy mindent tegyél <code>internal</code>-lá, amíg valamit kifejezetten nem tervezel újrahasználni. Ez egy logikus megközelítés és használhatod, ha úgy döntesz. De a legtöbb C# programozó egy másik megközelítést követ:</p><p>Három lépésben kell eldöntenünk a megosztás vagy nem megosztás kérdését:</p><ol><li>Megosztod-e a teljes projektet?</li><li>Megosztod-e az adott típusdefiníciót?</li><li>Megosztod-e a specifikus tagot, mint egy mezőt vagy metódust?</li></ol><p>A C# programozók általában ezeket a különböző szinteket elkülönítve vizsgálják.</p><p>Az <code>internal</code> említésére azért került sor, mert ez az alapértelmezett hozzáférési szint egy típus esetében, ha nincs explicit módon megadva. Az tanácsom az, hogy mindig írd ki a szándékolt hozzáférési szintet, ahelyett, hogy a defaultra hagynád. Ez arra kényszerít, hogy kialakítsd a szokást, hogy tudatosan döntsd el az elérési szinteket, ahelyett, hogy a véletlenre bíznád. Ha később úgy döntesz, hogy néhány hónap múlva inkább a defaultot használod, akkor abbahagyhatod az explicit megadást.</p>`,71),o=[l];function p(i,c){return a(),s("div",null,o)}const d=n(t,[["render",p],["__file","lesson5.html.vue"]]);export{d as default};
